using UnityEngine;

public class CoreLoopPrototype : MonoBehaviour
{
    public GameObject player;
    public GameObject collectible;
    public GameObject enemy;
    public GameObject goal;

    public int score = 0;
    public int health = 100;
    public bool hasKey = false;
    public bool levelComplete = false;

    void Start()
    {
        Debug.Log("=== Core Loop Prototype ===");
        Debug.Log("Player: " + player.name);
        Debug.Log("Score: " + score);
        Debug.Log("Health: " + health);

        // Core loop: Move → Collect → Survive → Progress
    }

    void Update()
    {
        if (Input.GetKeyDown(KeyCode.Space))
        {
            // Simulate collecting
            CollectItem();
        }
        if (Input.GetKeyDown(KeyCode.H))
        {
            // Simulate taking damage
            TakeDamage(10);
        }
        if (Input.GetKeyDown(KeyCode.W))
        {
            // Simulate winning
            WinLevel();
        }
    }

    void CollectItem()
    {
        score += 10;
        Debug.Log("Collected! Score: " + score);

        if (score >= 50)
        {
            hasKey = true;
            Debug.Log("You found the key!");
        }
    }

    void TakeDamage(int damage)
    {
        health -= damage;
        if (health < 0) health = 0;
        Debug.Log("Took " + damage + " damage! Health: " + health);

        if (health <= 0)
        {
            Debug.Log("💀 Game Over!");
        }
    }

    void WinLevel()
    {
        if (hasKey)
        {
            levelComplete = true;
            Debug.Log("🎉 Level Complete! Score: " + score);
        }
        else
        {
            Debug.Log("You need the key to win!");
        }
    }
}

